1	import { defineStore } from 'pinia'
2	import { ref, computed } from 'vue'
3	import api from '../api/index.js'
4	
5	export const useNotificationStore = defineStore('notifications', () => {
6	  const notifications = ref([])
7	  const unreadCount = ref(0)
8	  const preferences = ref(null)
9	  let pollInterval = null
10	
11	  const unread = computed(() => notifications.value.filter(n => !n.is_read))
12	
13	  async function fetchUnreadCount() {
14	    try {
15	      const res = await api.get('/notifications/unread-count')
16	      unreadCount.value = res.data.count ?? 0
17	    } catch { /* offline */ }
18	  }
19	
20	  async function fetchNotifications(params = {}) {
21	    try {
22	      const res = await api.get('/notifications', { params })
23	      notifications.value = res.data
24	      unreadCount.value = res.data.filter(n => !n.is_read).length
25	    } catch { /* offline */ }
26	  }
27	
28	  async function markRead(id) {
29	    await api.patch(`/notifications/${id}/read`)
30	    const n = notifications.value.find(n => n.id === id)
31	    if (n) { n.is_read = true; unreadCount.value = Math.max(0, unreadCount.value - 1) }
32	  }
33	
34	  async function markAllRead() {
35	    await api.post('/notifications/mark-all-read')
36	    notifications.value.forEach(n => n.is_read = true)
37	    unreadCount.value = 0
38	  }
39	
40	  async function deleteNotification(id) {
41	    await api.delete(`/notifications/${id}`)
42	    notifications.value = notifications.value.filter(n => n.id !== id)
43	  }
44	
45	  async function fetchPreferences() {
46	    try {
47	      const res = await api.get('/notifications/preferences/me')
48	      preferences.value = res.data
49	    } catch { /* offline */ }
50	  }
51	
52	  async function savePreferences(prefs) {
53	    const res = await api.put('/notifications/preferences/me', prefs)
54	    preferences.value = res.data
55	  }
56	
57	  function startPolling(intervalMs = 30000) {
58	    fetchUnreadCount()
59	    pollInterval = setInterval(fetchUnreadCount, intervalMs)
60	  }
61	
62	  function stopPolling() {
63	    if (pollInterval) { clearInterval(pollInterval); pollInterval = null }
64	  }
65	
66	  return {
67	    notifications, unreadCount, preferences, unread,
68	    fetchUnreadCount, fetchNotifications, markRead, markAllRead,
69	    deleteNotification, fetchPreferences, savePreferences,
70	    startPolling, stopPolling,
71	  }
72	})
