describe('CMSView — revision list (newest first)', () => {
  const revisions = [
    { id: 1, revision_number: 1, created_at: '2024-01-01T00:00:00Z', change_note: 'initial' },
    { id: 2, revision_number: 2, created_at: '2024-01-02T00:00:00Z', change_note: 'edit 1' },
